sys_script_vtable.script:
(function executeQuery(v_table, v_query) {

    // INTRODUCING THE SHOWSSPOTTER

    var IMG_URL = "https://image.tmdb.org/t/p/w500";

    /********** fetchShowsFuncResp(): Fetch movies dynamically like list of 'Latest Popular Shows', single 'Latest Popular Shows', and search desired movie *********/

    function fetchShowsDynamically({
        restMessage,
        restMethod,
        id,
        showName
    }) {
        try {
            var r = new sn_ws.RESTMessageV2(restMessage, restMethod);
            r.setStringParameterNoEscape('api_key', gs.getProperty('x_1962882_show_s_0.showSpotter.api.key'));
            if (id) r.setStringParameterNoEscape('showId', id);
            if (showName) r.setQueryParameter('query', showName);

            var response = r.execute();
            var responseBody = response.getBody();
            var httpStatus = response.getStatusCode();
            return {
                'responseData': responseBody ? JSON.parse(responseBody) : [],
                'httpStatus': httpStatus
            };
        } catch (ex) {
            var message = ex.message;
            gs.addErrorMessage(message);
        }
    }

    /******** Push list of movies in a list view of the remote table or push single movie in form view *******/

    function pushDataToTable({
        showData,
        requestedSys
    }) {
        try {
            var movieRatingArr = showData.vote_average.toString().split('.');
            var str;
            var genresArr = [];
            var posterUrl = IMG_URL + showData.poster_path;
            if (showData.genres && showData.genres.length > 0) {
                showData.genres.map(function(item) {
                    genresArr.push(item.name);
                });
            }
            var rowObj = {
                sys_id: requestedSys ? requestedSys : showData.id + "_" + gs.generateGUID(),
                name: showData.title,
                id: showData.id,
                overview: showData.overview,
                rating: movieRatingArr[1] ? movieRatingArr[0] + '.' + movieRatingArr[1].slice(0, 1) : movieRatingArr[0],
                release_date: showData.release_date,
                genres: genresArr.join(', '),
                poster: '<img src="' + posterUrl + '" width="180" />',
                category: v_query.getCondition('category') && v_query.getCondition('category').split('=')[1]
            };
            v_table.addRow(rowObj);
        } catch (ex) {
            var message = ex.message;
            gs.addErrorMessage(message);
        }
    }

    /******** Dynamically calling the APIs and pushing data in the remote table based on the logic ********/

    try {
        var searchedShowName = v_query.getCondition('name') && v_query.getCondition('name').split('=')[1];
        if (searchedShowName) {
            var searchShowFuncResp = fetchShowsDynamically({
                restMessage: 'SHOW-SPOTTER',
                restMethod: 'Search Shows',
                showName: searchedShowName
            });
            if (searchShowFuncResp.httpStatus == '200') {
                searchShowFuncResp.responseData.results.forEach(function(item) {
                    pushDataToTable({
                        showData: item
                    });
                });
            }
            gs.addInfoMessage('<span style="color: #2e7d32;">&#10003;</span> <b>RESULTS FOR ' + searchedShowName.toUpperCase() + '</b>');
        } else if (v_query.getSysId()) {
            var fetchSingleShowFuncResp = fetchShowsDynamically({
                restMessage: 'SHOW-SPOTTER',
                restMethod: 'Search Single Show',
                id: v_query.getSysId().split('_')[0]
            });
            var showObj = fetchSingleShowFuncResp.responseData;
            if (fetchSingleShowFuncResp.httpStatus == '200') {
                pushDataToTable({
                    showData: showObj,
                    requestedSys: v_query.getSysId()
                });
                if (new x_1962882_show_s_0.ShowSpotterDAO().validateMyWatchList(showObj)) {
                    gs.addInfoMessage('<span style="color: #2e7d32;">&#10003;</span> ' + '<b>' + showObj.title + '</b>' + ' is already in your watchlist.');
                }
            }
        } else {
            var selectedCategory = v_query.getCondition('category') && v_query.getCondition('category').split('=')[1];
            var fetchShowsFuncResp;
            if (selectedCategory == '1') { // Latest Popular Movies
                fetchShowsFuncResp = fetchShowsDynamically({
                    restMessage: 'SHOW-SPOTTER',
                    restMethod: 'Latest Popular Movies'
                });
                gs.addInfoMessage('<span style="color: #2e7d32;">&#10003;</span> <b>LATEST POPULAR MOVIES</b>');
            } else if (selectedCategory == '2') { // Top Rated Movies
                fetchShowsFuncResp = fetchShowsDynamically({
                    restMessage: 'SHOW-SPOTTER',
                    restMethod: 'Top Rated Movies'
                });
                gs.addInfoMessage('<span style="color: #2e7d32;">&#10003;</span> <b>TOP RATED MOVIES</b>');
            } else if (selectedCategory == '3') { // Upcoming Movies
                fetchShowsFuncResp = fetchShowsDynamically({
                    restMessage: 'SHOW-SPOTTER',
                    restMethod: 'Upcoming Movies'
                });
                gs.addInfoMessage('<span style="color: #2e7d32;">&#10003;</span> <b>UPCOMING MOVIES</b>');
            } else if (selectedCategory == '4') { // Now Playing
                fetchShowsFuncResp = fetchShowsDynamically({
                    restMessage: 'SHOW-SPOTTER',
                    restMethod: 'Now Playing Movies'
                });
                gs.addInfoMessage('<span style="color: #2e7d32;">&#10003;</span> <b>CURRENTLY IN THEATRES</b>');
            }
            if (fetchShowsFuncResp.httpStatus == '200') {
                var showsArr = fetchShowsFuncResp.responseData.results;
                if (showsArr) {
                    showsArr.forEach(function(show) {
                        pushDataToTable({
                            showData: show
                        });
                    });
                }
            }
        }
    } catch (ex) {
        var message = ex.message;
        gs.addErrorMessage(message);
    }

})(v_table, v_query);

